import { useEffect, useState } from 'react';
import Layout from '../components/Layout';
import { bolgeAPI } from '../api';

const DURUM_BADGE = { yolda: 'badge-info', ulastu: 'badge-warning', tamamlandi: 'badge-success', YOLDA: 'badge-info', ULASTU: 'badge-warning', TAMAMLANDI: 'badge-success' };
const DURUM_TR = { yolda: '🚛 Yolda', ulastu: '✅ Ulaştı', tamamlandi: '🏁 Tamamlandı', YOLDA: '🚛 Yolda', ULASTU: '✅ Ulaştı', TAMAMLANDI: '🏁 Tamamlandı' };

export default function BolgeTirlar() {
  const [tirlar, setTirlar] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    bolgeAPI.getTirlar().then(r => setTirlar(r.data)).catch(() => {}).finally(() => setLoading(false));
  }, []);

  return (
    <Layout title="Bölge Tır Takibi">
      <div className="card">
        <div className="card-header">
          <div className="card-title">Tırlar ({tirlar.length})</div>
        </div>
        {loading ? <div className="loading"><div className="spinner" /></div> : (
          <div className="table-wrapper">
            <table>
              <thead>
                <tr><th>Plaka</th><th>Durum</th><th>Kaynak</th><th>Hedef</th><th>Şoför</th><th>Tarih</th></tr>
              </thead>
              <tbody>
                {tirlar.map(t => (
                  <tr key={t.id}>
                    <td style={{ fontFamily: 'IBM Plex Mono', fontWeight: 700 }}>{t.plaka}</td>
                    <td><span className={`badge ${DURUM_BADGE[t.durum] || 'badge-neutral'}`}>{DURUM_TR[t.durum] || t.durum}</span></td>
                    <td style={{ fontSize: 12 }}>{t.kaynak_merkez?.ad} <span style={{ color: 'var(--text3)' }}>({t.kaynak_merkez?.il})</span></td>
                    <td style={{ fontSize: 12 }}>{t.hedef_merkez?.ad} <span style={{ color: 'var(--text3)' }}>({t.hedef_merkez?.il})</span></td>
                    <td style={{ fontSize: 12 }}>{t.sofor_ad || '—'}</td>
                    <td style={{ fontSize: 11, color: 'var(--text3)', fontFamily: 'IBM Plex Mono' }}>{new Date(t.created_at).toLocaleDateString('tr-TR')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </Layout>
  );
}
